(function () {
  'use strict';

  var email = 'skillsprintconsulting@gmail.com';

  function restoreEmailLinks() {
    document.querySelectorAll('a[href*="/cdn-cgi/l/email-protection"]').forEach(function (link) {
      link.href = 'mailto:' + email;
      link.setAttribute('aria-label', 'Email ' + email);

      var protectedText = link.querySelector('.__cf_email__');
      if (protectedText) {
        protectedText.textContent = email;
        protectedText.classList.remove('__cf_email__');
        protectedText.removeAttribute('data-cfemail');
      } else if (/email\s*protected/i.test(link.textContent)) {
        link.textContent = email;
      }
    });

    document.querySelectorAll('.__cf_email__').forEach(function (protectedText) {
      protectedText.textContent = email;
      protectedText.classList.remove('__cf_email__');
      protectedText.removeAttribute('data-cfemail');

      var link = protectedText.closest('a');
      if (link) {
        link.href = 'mailto:' + email;
        link.setAttribute('aria-label', 'Email ' + email);
      }
    });
  }

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', restoreEmailLinks, { once: true });
  } else {
    restoreEmailLinks();
  }
}());
